import re
from typing import Dict, Any

# --- 1. Tokenization (Lexer) ---

class Token:
    def __init__(self, type: str, value: Any = None):
        self.type = type  # e.g., 'NUMBER', 'IDENTIFIER', 'PLUS', 'LPAREN'
        self.value = value

    def __repr__(self):
        return f"Token({self.type}, {repr(self.value)})"

token_specification = [
    r'\s+',             # Whitespace (ignored)
    ('NUMBER', r'\d+(\.\d*)?'),  # Integer and float literals
    ('STRING', r'"[^"]*"'),   # Not needed, but good practice
    ('NAME', r'[a-zA-Z_][a-zA-Z0-9]*'), # Identifiers (variables, functions)
    ('OP', r'==|!=|<=|>=|\+|\-|\*|\/|\*\*|%|\(|\)|<|>'), # Operators and parentheses
]

TOKEN_REGEX = '|'.join(f'(?P<{name}>{pattern})' for name, pattern in token_specification)
TOKEN_MATCHES = re.compile(TOKEN_REGEX)

def tokenize(text: str) -> list[Token]:
    tokens = []
    # Adjust operators to separate them properly if regex groups overlap or miss precedence
    # We manually parse operators since the combined regex might treat '==' as part of NAME 
    # if not structured carefully. Let's rely on careful matching pattern replacement.

    # Overwrite simplistic operator parsing for better handling of multi-char ops:
    text = text.replace('++', '+').replace('--', ' - ').replace('*', ' * ').replace('/', ' / ')
    text = re.sub(r'\s+', ' ', text).strip() 

    # Re-run tokenization using a more robust method targeting known tokens
    tokens_list = []
    remaining_str = text

    while remaining_str:
        match = TOKEN_MATCHES.match(remaining_str)
        if match:
            token_type = match.lastgroup[1] if match.lastgroup else None
            value_str = match.group(0).strip()

            if not value_str or value_str.isspace(): # Handle whitespace only matches (should be prevented by regex)
                 remaining_str = remaining_str[len(match.group(0)):].lstrip()
                 continue

            # Categorize the token type
            token_value: Any = None
            if re.match(r'^\d+(\.\d*)?$', value_str):
                token_type = 'NUMBER'
                try:
                    token_value = float(value_str) if '.' in value_str and 'e' not in value_str else int(float(value_str))
                except ValueError:
                     # Fallback for pure integers that passed float check
                     if value_str.isdigit():
                        token_value = int(value_str)
                    else:
                        raise SyntaxError(f"Invalid number format: {value_str}")

            elif re.match(r'^[a-zA-Z_][a-zA-Z0-9]*$', value_str):
                if value_str in ('+', '-', '*', '/', '**', '%', '<=', '==', '!=', '>=', '<', '>', '(', ')'):
                    token_type = 'OP'
                elif value_str in ('abs', 'min', 'max', 'round'):
                     token_type = 'NAME' # Function name
                else:
                    token_type = 'NAME' # Variable name

            elif value_str in ['+', '-', '*', '/', '**', '%']:
                 token_type = 'OP'
            elif value_str == '(' or value_str == ')':
                token_type = 'LPAREN' if value_str == '(' else 'RPAREN'
            else:
                # Must be an operator that fell through (like > or <=)
                 if any(op in value_str for op in ['==', '!=', '<=', '>=']):
                     token_type = 'OP'
                 elif value_str.isalnum():
                      # Should have been caught above, but defensive measure
                      token_type = 'NAME'
                 else:
                    raise SyntaxError(f"Unknown token: {value_str}")

            # Special handling for unary minus/plus parsing based on context usually handled during parsing, 
            # but here we simplify and let the parser handle it.

            tokens_list.append(Token(token_type, token_value))
        else:
            raise SyntaxError(f"Illegal character at: {remaining_str[0]}")

        # Move past the matched text segment
        match = TOKEN_MATCHES.match(remaining_str)
        if match:
             remaining_str = remaining_str[len(match.group(0)):].strip()
        else:
            break # Should not happen if regex covers all cases

    # Post-processing Pass to correctly classify initial '-' as UNARY_MINUS 
    # (This is a common approach simplification for Pratt parsers)
    final_tokens = []
    is_start_of_expression = True
    for i, token in enumerate(tokens):
        if token.type == 'OP' and token.value == '-' and is_start_of_expression:
             # Check if it follows an opening parenthesis or is the start of the input
            prev_type = final_tokens[-1].type if final_tokens else None

            # Simplified heuristic check for unary minus: 
            # It's unary if it's at the start, after '(', or after another operator (e.g., x * -y)
            if i == 0 or prev_type in ('LPAREN', 'OP'):
                token.type = 'MINUS' # Use a dedicated type for Unary Minus
        final_tokens.append(token)
        is_start_of_expression = is_start_of_expression and (token.type != 'NAME' and token.type != 'NUMBER')

